sp_widget.client_script:
api.controller=function($scope) {
	/* widget controller */
	var c = this;
	c.data.active = true;
	c.data.category = c.data.passCategory;
	c.data.products = c.data.passProducts;

	$scope.filterCategory = function(cate) {
		if(cate == undefined){
			c.data.active = true;
			c.data.products = c.data.passProducts;
		}else{
			c.data.active = false;
			c.data.catFilter = cate; 
			c.server.update().then(function(response) {
				c.data.products = c.data.teste;
			});
		}

	};

	console.log(JSON.stringify(c.data.category));
};

sp_widget.css:
*,
*::before,
*::after {
  box-sizing: border-box;
}

body {
  color: #272727;
  font-style: normal;
  font-weight: 400;
  letter-spacing: 0;
  padding: 1rem;
}

.main{
  max-width: 1200px;
  margin: 0 auto;
}

.header {
	margin-bottom 10px;
}
.header .btn {
  height: 40px;
  color: #22cff0;
  background: lighten(#22cff0, 40%);
  border: 1px solid #22cff0;
  border-radius: 15px;
  margin-bottom:5px;
  margin-left:5px;
  transition: all 0.4s;
}

.header .btn:hover {
  color: lighten(#22cff0, 90%);
  background: #22cff0;
  border: 1px solid lighten(#22cff0, 90%);
  cursor: pointer;
}


.header .active {
  color: lighten(#22cff0, 90%);
  background: #22cff0;
  border: 1px solid lighten(#22cff0, 90%);
  cursor: pointer;
}

.header .active, .header .btn:hover {
	-webkit-transform: translateY(3px);
  -ms-transform: translateY(3px);
  transform: translateY(3px);
} 

h1 {
  color: #1f4287;
  font-size: 44px;
  text-align: center;
}

.card_image {
  height: 170px;
  overflow: hidden;
  display: flex;
  justify-content: center;
  align-items: center; 
  position: relative;
}

img {
  width: 200px;
}

.marca {
  background: #f9b305;
  padding: 5px 10px;
  border-radius: 0.75rem;
  color: #fff;
  position: absolute;
  bottom: 5px;
  right: 5px;  
  font-weight: 200;   
}

.card_content .btn {
  color: #ffffff;
  padding: 0.5rem;
  font-size: 12px;
  text-transform: uppercase;
  border-radius: 0.75rem;
  font-weight: 400;
  display: block;
  width: 100%;
  cursor: pointer;
  border: 1px solid rgba(255, 255, 255, 0.2);
  background: transparent;
}

.card_content .btn:hover {
  background-color: rgba(255, 255, 255, 0.32);
}

.cards {
  display: flex;
  flex-wrap: wrap;
  list-style: none;
  margin: 0;
  padding: 0;
  justify-content: center;
  transition: all 0.9s ;
}

.cards_item {
  display: flex;
  padding: 1rem;
  height: 300px;
  width: 200px !important;
  transition: all 0.45s;
}

.cards_item:hover {
  transition: all .45s;
  transform: translate3d(0, -5px, 0);
}

.card {
  background-color: white;
  border-radius: 0.75rem;
  box-shadow: 0 20px 40px -14px rgba(0, 0, 0, 0.25);
  display: flex;
  flex-direction: column;
  overflow: hidden;
  width: 200px;
  align-self: flex-end;
  transition: all 0.35s;
  /*animation: fadeOut 1s linear;*/
}

@keyframes fadeOut {
  0% {
    opacity: 1; /* Start fully visible */
    visibility: visible;
  }
  100% {
    opacity: 0; /* End completely transparent */
    visibility: hidden; /* Hide completely at the end */
  }
}

.card_content {
  height: 110px;
  padding: 1rem;
  background: linear-gradient(to bottom left, #68b049 40%, #7ed957 100%);
}

.card_title {
  color: #ffffff;
  font-size: 1.5rem;
  font-weight: 700;
  letter-spacing: 1px;
  text-transform: capitalize;
  margin: 0px;

  display: -webkit-box;
  -webkit-line-clamp: 1;
  -webkit-box-orient: vertical;
  overflow: hidden;
  text-overflow: ellipsis;
}

.card_text {
  color: #ffffff;
  font-size: 1.05rem;
  line-height: 1.5;
  margin-top: 5px;
  margin-bottom: 1.1rem;    
  font-weight: 400;

  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
  text-overflow: ellipsis;
}
.made_by{
  font-weight: 400;
  font-size: 13px;
  margin-top: 35px;
  text-align: center;
}

sp_widget.script:
(function() {
	/* populate the 'data' object */
	/* e.g., data.table = $sp.getValue('table'); */


	function StartCategory(){
		var grCat = new GlideRecord('u_categoria');
		grCat.addEncodedQuery('u_ativo=true');
		grCat.query();
		var records = [];
		while (grCat.next()) {
			var rec = {};
			rec.sysID = grCat.getValue('sys_id');
			rec.categoria = grCat.getDisplayValue('u_categoria');
			records.push(rec);
		}
		return records;
	}

	function StartList(){
		var grList = new GlideRecord('u_produto');
		grList.setLimit(20);
		grList.query();
		var records = [];
		while (grList.next()) {
			var rec = {};
			rec.sysID = grList.getValue('sys_id');
			rec.nome = grList.getValue('u_nome');
			rec.categoria = grList.getDisplayValue('u_categoria');
			rec.imagem = grList.getValue('u_imagem');
			rec.marca = grList.getDisplayValue('u_marca');
			rec.descricao = grList.getValue('u_descricao');
			records.push(rec);
		}
		return records;
	}

	data.passCategory = StartCategory();
	data.passProducts = StartList();

	if (input && input.catFilter) {

		var catFilter = input.catFilter.sysID;

		var grList2 = new GlideRecord('u_produto');
		grList2.addEncodedQuery('u_categoria='+ catFilter);
		grList2.query();
		var records2 = [];
		while (grList2.next()) {
			var rec2 = {};
			rec2.sysID = grList2.getValue('sys_id');
			rec2.nome = grList2.getValue('u_nome');
			rec2.categoria = grList2.getDisplayValue('u_categoria');
			rec2.imagem = grList2.getValue('u_imagem');
			rec2.marca = grList2.getDisplayValue('u_marca');
			rec2.descricao = grList2.getValue('u_descricao');
			records2.push(rec2);
		}

		data.teste = records2;
	}

})();
